import{_ as t,o as i,c as o,ag as a}from"./chunks/framework.YaIgwL5o.js";const p=JSON.parse('{"title":"Your First Presentation","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/first-presentation.md","filePath":"tutorials/first-presentation.md"}'),n={name:"tutorials/first-presentation.md"};function l(r,e,s,d,c,h){return i(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="your-first-presentation" tabindex="-1">Your First Presentation <a class="header-anchor" href="#your-first-presentation" aria-label="Permalink to &quot;Your First Presentation&quot;">​</a></h1><p>This tutorial walks you through creating a complete presentation from scratch — from blank deck to exported HTML file.</p><h2 id="_1-creating-a-new-presentation" tabindex="-1">1. Creating a new presentation <a class="header-anchor" href="#_1-creating-a-new-presentation" aria-label="Permalink to &quot;1. Creating a new presentation&quot;">​</a></h2><ol><li>Open Slides Editor in your browser (default: <code>http://localhost:3002</code>).</li><li>On the home screen, click <strong>New Presentation</strong>.</li><li>A dialog appears asking you to name your presentation. Enter a name (e.g., &quot;My First Deck&quot;) and click <strong>Create</strong>.</li></ol><h2 id="_2-choosing-a-template" tabindex="-1">2. Choosing a template <a class="header-anchor" href="#_2-choosing-a-template" aria-label="Permalink to &quot;2. Choosing a template&quot;">​</a></h2><p>After clicking Create, you&#39;ll be offered a choice of starting templates:</p><ul><li><strong>Blank</strong> — a single empty slide with no pre-placed elements</li><li><strong>Title Slide</strong> — a slide with a centered title and subtitle placeholder</li><li><strong>Academic</strong> — title slide + outline slide with footer sequence</li><li><strong>Minimal</strong> — clean layout, single font, no decoration</li></ul><p>For this tutorial, choose <strong>Title Slide</strong>.</p><h2 id="_3-editing-the-title-slide" tabindex="-1">3. Editing the title slide <a class="header-anchor" href="#_3-editing-the-title-slide" aria-label="Permalink to &quot;3. Editing the title slide&quot;">​</a></h2><p>You&#39;ll see a slide with two text placeholders: a large title and a smaller subtitle.</p><ol><li><strong>Double-click the title</strong> (&quot;Click to add title&quot;) to enter edit mode.</li><li>Type your presentation title — for example, <em>Introduction to Reveal.js</em>.</li><li>Press <code>Escape</code> to finish editing the title.</li><li><strong>Double-click the subtitle</strong> and type your name or a short description.</li><li>Press <code>Escape</code> again.</li></ol><p>To change the font size:</p><ol><li>Double-click the title to re-enter edit mode.</li><li>Select all the text (<code>Ctrl+A</code>).</li><li>Use the font size box in the toolbar and change it to your preferred size.</li><li>Press <code>Escape</code>.</li></ol><h2 id="_4-adding-a-new-slide" tabindex="-1">4. Adding a new slide <a class="header-anchor" href="#_4-adding-a-new-slide" aria-label="Permalink to &quot;4. Adding a new slide&quot;">​</a></h2><ol><li>In the <strong>slide panel</strong> on the left, click the <strong>+</strong> button at the bottom, or right-click an existing slide and choose <strong>Add Slide After</strong>.</li><li>A new blank slide appears.</li><li>Click the new slide thumbnail to navigate to it.</li></ol><h2 id="_5-adding-a-text-box-and-an-image" tabindex="-1">5. Adding a text box and an image <a class="header-anchor" href="#_5-adding-a-text-box-and-an-image" aria-label="Permalink to &quot;5. Adding a text box and an image&quot;">​</a></h2><p><strong>Add a text box:</strong></p><ol><li>Right-click on the blank slide canvas and choose <strong>Insert → Text Box</strong>.</li><li>A text box appears. Double-click it and type some content.</li><li>Use the toolbar to format your text (bold, color, size, etc.).</li></ol><p><strong>Add an image:</strong></p><ol><li>Right-click on the canvas and choose <strong>Insert → Image</strong>.</li><li>A file picker opens. Choose an image from your computer.</li><li>The image appears on the slide. Drag it to position it, and drag the corners to resize.</li></ol><h2 id="_6-applying-a-theme" tabindex="-1">6. Applying a theme <a class="header-anchor" href="#_6-applying-a-theme" aria-label="Permalink to &quot;6. Applying a theme&quot;">​</a></h2><ol><li>Click the <strong>Design</strong> button in the top toolbar (or go to <strong>Slide → Theme</strong>).</li><li>The theme panel opens on the right, showing 11 built-in reveal.js themes.</li><li>Click <strong>Sky</strong> (or any theme you like) to apply it.</li><li>The background and typography update across all slides immediately.</li></ol><h2 id="_7-adding-a-slide-transition" tabindex="-1">7. Adding a slide transition <a class="header-anchor" href="#_7-adding-a-slide-transition" aria-label="Permalink to &quot;7. Adding a slide transition&quot;">​</a></h2><ol><li>Click on a slide in the left panel to select it.</li><li>Open the <strong>Slide Settings</strong> panel (right-click → Slide Properties, or the gear icon in the slide panel).</li><li>Under <strong>Transition</strong>, choose <strong>Fade</strong> from the dropdown.</li><li>You can also set the transition speed: Slow, Normal, or Fast.</li></ol><h2 id="_8-presenting" tabindex="-1">8. Presenting <a class="header-anchor" href="#_8-presenting" aria-label="Permalink to &quot;8. Presenting&quot;">​</a></h2><ol><li>Click the <strong>Present</strong> button (play icon) in the top toolbar, or press <code>F</code>.</li><li>The presentation enters full-screen mode via reveal.js.</li><li>Use the <strong>arrow keys</strong> to advance slides.</li><li>Press <strong>S</strong> to open the <strong>speaker notes</strong> window in a separate browser tab.</li><li>Press <strong>Escape</strong> to exit full-screen.</li></ol><h2 id="_9-exporting-as-html" tabindex="-1">9. Exporting as HTML <a class="header-anchor" href="#_9-exporting-as-html" aria-label="Permalink to &quot;9. Exporting as HTML&quot;">​</a></h2><ol><li>Click <strong>File → Export → HTML</strong>.</li><li>Save the <code>.html</code> file to your computer.</li><li>Open the file in any browser — your presentation is self-contained and shareable.</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>If you plan to present without an internet connection (e.g., at a conference), choose <strong>File → Export → Offline HTML</strong> instead to inline all assets.</p></div><p>Congratulations — you&#39;ve built and exported your first presentation!</p><p><strong>Next steps:</strong></p><ul><li><a href="/revealjs_gui/tutorials/academic-slides.html">Academic Slides tutorial</a> — footers, LaTeX, two-column layouts</li><li><a href="/revealjs_gui/tutorials/using-latex.html">Using LaTeX &amp; Math</a> — deep dive on equations and TikZ diagrams</li></ul>',32)])])}const u=t(n,[["render",l]]);export{p as __pageData,u as default};
